@namespace Lumeo
@inject Lumeo.Services.IComponentInteropService Interop

@{
    var context = new StepsContext(CurrentStep, Clickable, EventCallback.Factory.Create<int>(this, OnStepClick), Orientation, Animated, _direction, _replayKey, this);
}

<div class="@CssClass" id="@_stepsId" role="list" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> CurrentStepChanged { get; set; }
    [Parameter] public bool Clickable { get; set; }
    [Parameter] public Lumeo.Orientation Orientation { get; set; } = Lumeo.Orientation.Horizontal;

    /// <summary>
    /// When true, enables opt-in motion: the current step's indicator pulses,
    /// connector lines draw in on advance, and retract on reverse. Default is
    /// <c>false</c> (no animation, original behaviour).
    /// </summary>
    [Parameter] public bool Animated { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Identity-keyed item registry (#244). Each StepsItem registers itself once
    // in OnInitialized and reads its index back from this ordered list, so the
    // index stays stable across independent child re-renders. The previous
    // model reset a counter in the parent's render block and incremented it
    // from each item's OnParametersSet — an item re-rendering on its own (e.g.
    // a changed Status) without a preceding parent reset drifted every
    // subsequent item's number.
    private readonly List<StepsItem> _items = new();

    // A stable container id so the after-render DOM-order probe has an anchor.
    private readonly string _stepsId = LumeoIds.New("steps");

    // step-indicator id -> live DOM index, refreshed after each render. The mount-
    // order registry (_items) is stable across independent child re-renders (#244)
    // but a keyed REORDER of the StepsItem children MOVES them in the DOM without
    // re-registering, so the registry index goes stale and the number / completed-
    // current status / click target / aria-label all drift (#43/#44). After each
    // render we read the real DOM order and, if it differs, re-render so every
    // _index resolves to the item's true DOM position. Empty until the first probe
    // (and whenever JS is unavailable) -> GetItemIndex falls back to registry order,
    // so the non-reordered common case is unchanged and prerender/JS-off still work.
    private Dictionary<string, int> _domOrder = new();

    // Direction tracking for opt-in Animated mode. `_direction` drives which
    // keyframe the connector plays (forward draw-in vs. backward unwind).
    // `_replayKey` is bumped every time CurrentStep actually changes so that
    // `@key` on the connector forces the animation to re-fire on each click.
    private int _lastCurrentStep;
    private StepsDirection _direction = StepsDirection.Forward;
    private int _replayKey;
    private bool _initialized;

    internal void RegisterItem(StepsItem item)
    {
        if (!_items.Contains(item))
            _items.Add(item);
    }

    internal void UnregisterItem(StepsItem item) => _items.Remove(item);

    internal int GetItemIndex(StepsItem item)
    {
        // Live DOM order wins (survives a keyed reorder); fall back to mount order.
        if (_domOrder.TryGetValue(item.StepId, out var domIdx)) return domIdx;
        var idx = _items.IndexOf(item);
        return idx < 0 ? 0 : idx;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // NOTE: a Loose-mode JSInterop returns NULL for an unconfigured string[] call.
        string[]? ids;
        try
        {
            ids = await Interop.GetOrderedDescendantIds(_stepsId, "[data-step-indicator]");
        }
        catch (JSDisconnectedException) { return; }
        catch (ObjectDisposedException) { return; }
        catch (InvalidOperationException) { return; } // JS unavailable (prerender)

        if (ids is not { Length: > 0 }) return;

        var map = new Dictionary<string, int>(ids.Length);
        for (var i = 0; i < ids.Length; i++) map[ids[i]] = i;

        // Re-render ONLY when the live DOM order actually changed, so a non-reordered
        // Steps never loops (renumbering changes text, not element order, so the next
        // probe returns the same order and converges).
        if (map.Count == _domOrder.Count && !map.Except(_domOrder).Any()) return;
        _domOrder = map;
        StateHasChanged();
    }

    protected override void OnParametersSet()
    {
        if (!_initialized)
        {
            _lastCurrentStep = CurrentStep;
            _initialized = true;
            return;
        }

        if (CurrentStep != _lastCurrentStep)
        {
            // Only treat single-step decrements as "backward" — these get the
            // unwind animation on the one connector that just lost its
            // completed state. Multi-step jumps (e.g. a demo timer wrapping
            // 3 -> 0) would only animate ONE connector while the others
            // silently flip from bg-primary to bg-border, AND the unwound
            // connector would be permanently stuck at scaleX(0) because the
            // animation has fill-mode: both. Skip the animation in that case
            // — direction stays Forward, connectors render static defaultColor.
            _direction = (CurrentStep < _lastCurrentStep && _lastCurrentStep - CurrentStep == 1)
                ? StepsDirection.Backward
                : StepsDirection.Forward;
            _lastCurrentStep = CurrentStep;
            _replayKey++;
        }
    }

    private string CssClass => Orientation switch
    {
        Lumeo.Orientation.Vertical => Cx.Merge("flex flex-col gap-0", Class),
        _ => Cx.Merge("flex flex-row items-start", Class)
    };

    private async Task OnStepClick(int step)
    {
        if (Clickable)
        {
            CurrentStep = step;
            await CurrentStepChanged.InvokeAsync(step);
        }
    }

    /// <summary>Direction of the user's most recent step transition. Drives
    /// the animated connector keyframes (forward draw vs reverse unwind).
    /// Component-specific (not a navigation direction in the cardinal sense),
    /// so intentionally NOT replaced by <see cref="Lumeo.Side"/>.</summary>
    public enum StepsDirection { Forward, Backward }

    public record StepsContext(int CurrentStep, bool Clickable, EventCallback<int> OnStepClick, Lumeo.Orientation Orientation, bool Animated, StepsDirection Direction, int ReplayKey, Steps Parent);
}

@namespace Lumeo
@implements IDisposable

@{
    // Re-read the stable registry index every render so it stays correct when
    // items are added/removed (the registry list is the single source of truth
    // for ordering — see Steps.GetItemIndex / #244).
    _index = Context?.Parent is not null ? Context.Parent.GetItemIndex(this) : 0;
    var status = GetStatus();
    var isHorizontal = Context?.Orientation != Lumeo.Orientation.Vertical;
    var isError = Status == StepsItemStatus.Error && status == StepStatus.Current;

    // The indicator's inner glyph (icon / check / error X / step number) is the
    // same regardless of whether the indicator is an interactive <button> or a
    // non-interactive <div>, so author it once and reuse it below.
    RenderFragment indicatorBody = @<text>
        @if (IconContent is not null)
        {
            @IconContent
        }
        else if (isError)
        {
            <SvgGlyph Svg="@(LumeoIcons.X)" class="h-4 w-4" />
        }
        else if (status == StepStatus.Completed)
        {
            <SvgGlyph Svg="@(LumeoIcons.Check)" class="h-4 w-4" />
        }
        else
        {
            <span>@(_index + 1)</span>
        }
    </text>;
}

@if (isHorizontal)
{
    <div class="@HorizontalCssClass" role="listitem" @attributes="AdditionalAttributes">
        <div class="flex flex-col items-center">
            @if (IsClickable)
            {
                <button type="button"
                        class="@GetIndicatorClasses(status, isError)" id="@_stepId" data-step-indicator="step"
                        aria-current="@(status == StepStatus.Current ? "step" : null)"
                        aria-label="@StepAriaLabel(status, isError)"
                        @onclick="HandleClick">
                    @indicatorBody
                </button>
            }
            else
            {
                <div class="@GetIndicatorClasses(status, isError)" id="@_stepId" data-step-indicator="step"
                     aria-current="@(status == StepStatus.Current ? "step" : null)"
                     aria-label="@StepAriaLabel(status, isError)">
                    @indicatorBody
                </div>
            }
            <div class="mt-2 text-center">
                @if (!string.IsNullOrEmpty(Title))
                {
                    <p class="@GetTitleClasses(status, isError)">@Title</p>
                }
                @if (!string.IsNullOrEmpty(Description))
                {
                    <p class="text-xs text-muted-foreground">@Description</p>
                }
            </div>
        </div>
        <div class="mx-2 mt-4 h-px flex-1 @GetLineClasses(status)" @key="@($"line-h-{_index}-{status}")"></div>
    </div>
}
else
{
    <div class="@VerticalCssClass" role="listitem" @attributes="AdditionalAttributes">
        <div class="flex flex-col items-center">
            @if (IsClickable)
            {
                <button type="button"
                        class="@GetIndicatorClasses(status, isError)" id="@_stepId" data-step-indicator="step"
                        aria-current="@(status == StepStatus.Current ? "step" : null)"
                        aria-label="@StepAriaLabel(status, isError)"
                        @onclick="HandleClick">
                    @indicatorBody
                </button>
            }
            else
            {
                <div class="@GetIndicatorClasses(status, isError)" id="@_stepId" data-step-indicator="step"
                     aria-current="@(status == StepStatus.Current ? "step" : null)"
                     aria-label="@StepAriaLabel(status, isError)">
                    @indicatorBody
                </div>
            }
            <div class="my-1 w-px flex-1 @GetLineClasses(status)" @key="@($"line-v-{_index}-{status}")"></div>
        </div>
        <div class="ms-3 pb-6">
            @if (!string.IsNullOrEmpty(Title))
            {
                <p class="@GetTitleClasses(status, isError)">@Title</p>
            }
            @if (!string.IsNullOrEmpty(Description))
            {
                <p class="text-xs text-muted-foreground">@Description</p>
            }
        </div>
    </div>
}

@*
    The step indicator is a real <button> ONLY when the Steps is Clickable.
    When it is NOT clickable a disabled <button> would be dropped from the tab
    order AND ignored by assistive technology, taking the aria-current="step"
    marker and the descriptive aria-label with it. So render a non-interactive
    <div> (still carrying aria-current/aria-label) in that case so the
    current-step status stays reachable/announceable. (#45)
*@
@code {
    [CascadingParameter] public Steps.StepsContext? Context { get; set; }
    [Parameter] public string? Title { get; set; }
    [Parameter] public string? Description { get; set; }
    [Parameter] public StepsItemStatus Status { get; set; } = StepsItemStatus.Default;

    /// <summary>Icon slot. Named <c>IconContent</c> to avoid shadowing the <c>&lt;Icon&gt;</c> component.</summary>
    [Parameter] public RenderFragment? IconContent { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private int _index;
    private Steps? _registeredParent;

    // Stable per-item id, rendered as the indicator's id + a data-step-indicator
    // marker so the parent's after-render DOM-order probe can resolve this item's
    // true DOM position even after a keyed reorder (#43/#44).
    private readonly string _stepId = LumeoIds.New("step");
    internal string StepId => _stepId;

    protected override void OnInitialized()
    {
        // Register once with the parent on mount; identity (this) keys the
        // stable index, so the slot survives independent re-renders.
        _registeredParent = Context?.Parent;
        _registeredParent?.RegisterItem(this);
    }

    public void Dispose() => _registeredParent?.UnregisterItem(this);

    private bool IsClickable => Context?.Clickable == true;
    private bool IsAnimated => Context?.Animated == true;

    private StepStatus GetStatus()
    {
        var current = Context?.CurrentStep ?? 0;
        if (_index < current) return StepStatus.Completed;
        if (_index == current) return StepStatus.Current;
        return StepStatus.Future;
    }

    private string GetIndicatorClasses(StepStatus status, bool isError)
    {
        var baseClasses = isError
            ? "flex h-8 w-8 shrink-0 items-center justify-center rounded-[calc(var(--radius)*2)] border-2 border-destructive bg-background text-destructive"
            : status switch
            {
                StepStatus.Completed => "flex h-8 w-8 shrink-0 items-center justify-center rounded-[calc(var(--radius)*2)] bg-primary text-primary-foreground",
                StepStatus.Current => "flex h-8 w-8 shrink-0 items-center justify-center rounded-[calc(var(--radius)*2)] border-2 border-primary bg-background text-sm font-semibold text-primary",
                _ => "flex h-8 w-8 shrink-0 items-center justify-center rounded-[calc(var(--radius)*2)] bg-muted text-sm text-muted-foreground"
            };

        // Only the Current (active) indicator pulses, and only when not in an error state.
        if (IsAnimated && status == StepStatus.Current && !isError)
        {
            baseClasses += " lumeo-steps-pulse";
        }

        baseClasses += IsClickable
            ? " cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
            : " cursor-default";

        return baseClasses;
    }

    private string GetTitleClasses(StepStatus status, bool isError) =>
        isError
            ? "text-sm font-semibold text-destructive"
            : status switch
            {
                StepStatus.Completed => "text-sm font-medium text-foreground",
                StepStatus.Current => "text-sm font-semibold text-foreground",
                _ => "text-sm text-muted-foreground"
            };

    private string GetLineClasses(StepStatus status)
    {
        var defaultColor = status switch
        {
            StepStatus.Completed => "bg-primary",
            _ => "bg-border"
        };

        if (!IsAnimated)
        {
            return defaultColor;
        }

        var isVertical = Context?.Orientation == Lumeo.Orientation.Vertical;
        var isBackward = Context?.Direction == Steps.StepsDirection.Backward;

        // Only animate the SINGLE connector that just transitioned state.
        // Forward: connector at _index becomes completed when CurrentStep advances past it.
        // Backward: connector at _index == new CurrentStep was just un-completed.
        var current = Context?.CurrentStep ?? 0;

        // Forward draw-in: this connector is now completed AND was just lit up
        // (i.e. its index equals the new-current-1 — the one we just crossed).
        if (!isBackward && status == StepStatus.Completed && _index == current - 1)
        {
            return $"{defaultColor} " + (isVertical ? "lumeo-steps-line-draw-y" : "lumeo-steps-line-draw-x");
        }

        // Backward unwind: connector at new CurrentStep was completed, now pending.
        // Force bg-primary during the animation so the user sees a coloured
        // line retracting (otherwise it's a bg-border grey line shrinking
        // — invisible against the muted background).
        if (isBackward && status != StepStatus.Completed && _index == current)
        {
            return "bg-primary " + (isVertical ? "lumeo-steps-line-unwind-y" : "lumeo-steps-line-unwind-x");
        }

        return defaultColor;
    }

    private async Task HandleClick()
    {
        if (Context is not null && IsClickable)
        {
            await Context.OnStepClick.InvokeAsync(_index);
        }
    }

    private string StepAriaLabel(StepStatus status, bool isError)
    {
        var label = !string.IsNullOrEmpty(Title) ? Title! : $"Step {_index + 1}";
        var state = isError ? " (error)"
            : status == StepStatus.Completed ? " (completed)"
            : status == StepStatus.Current ? " (current)"
            : "";
        return label + state;
    }

    private string HorizontalCssClass => Cx.Merge("flex flex-1 flex-row last:flex-initial", Class);
    private string VerticalCssClass => Cx.Merge("flex flex-row", Class);

    private enum StepStatus { Completed, Current, Future }

    public enum StepsItemStatus { Default, Error }
}
